#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    using opt = fs::copy_options;

    // نسخ مجلد كامل مع استبدال الملفات الموجودة
    fs::copy(
        "project/src",
        "project/backup",
        opt::recursive | opt::overwrite_existing
    );

    // خيارات أخرى:
    // opt::skip_existing      — تخطي الملفات الموجودة
    // opt::update_existing    — استبدال إذا كان المصدر أحدث
    // opt::copy_symlinks      — نسخ الروابط كروابط
    // opt::directories_only   — نسخ المجلدات فقط بدون ملفات
}

#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // copy: يعمل على ملفات ومجلدات
    // copy_file: يعمل على ملفات فقط (أبسط وأوضح)

    // copy_file يرمي خطأ إذا الهدف موجود
    fs::copy_file("a.txt", "b.txt");

    // copy مع overwrite_existing يستبدل بدون خطأ
    fs::copy("a.txt", "b.txt", fs::copy_options::overwrite_existing);

    // copy ينسخ مجلدات، copy_file لا يستطيع
    // fs::copy_file("mydir", "backup"); // ❌ خطأ
    fs::copy("mydir", "backup", fs::copy_options::recursive); // ✅
}

