#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    try {
        auto size_before = fs::file_size("video.mp4");
        fs::copy_file("video.mp4", "video_copy.mp4",
                      fs::copy_options::overwrite_existing);
        auto size_after = fs::file_size("video_copy.mp4");

        std::cout << "الحجم الأصلي: " << size_before << " بايت" << '\n';
        std::cout << "حجم النسخة: " << size_after << " بايت" << '\n';
        std::cout << "مطابق: " << (size_before == size_after ? "نعم" : "لا") << '\n';
    } catch (const fs::filesystem_error& e) {
        std::cerr << "خطأ: " << e.what() << '\n';
    }
}

#include <iostream>
#include <filesystem>
#include <chrono>
#include <iomanip>
#include <ctime>
namespace fs = std::filesystem;

int main() {
    auto ftime = fs::last_write_time("main.cpp");

    // تحويل file_time_type لـ time_t
    auto sctp = std::chrono::time_point_cast<std::chrono::system_clock::duration>(
        ftime - fs::file_time_type::clock::now() + std::chrono::system_clock::now());
    std::time_t cftime = std::chrono::system_clock::to_time_t(sctp);

    std::cout << "آخر تعديل: " << std::put_time(std::localtime(&cftime), "%Y-%m-%d %H:%M:%S") << '\n';
}

#include <iostream>
#include <filesystem>
#include <string>
namespace fs = std::filesystem;

int main() {
    fs::path newest;
    fs::file_time_type latest_time;

    for (const auto& entry : fs::directory_iterator(".")) {
        auto ftime = fs::last_write_time(entry.path());
        if (newest.empty() || ftime > latest_time) {
            newest = entry.path();
            latest_time = ftime;
        }
    }
    std::cout << "أحدث ملف: " << newest.filename() << '\n';
}

#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // حفظ الوقت الأصلي
    auto original_time = fs::last_write_time("data.txt");

    // تغيير وقت التعديل للوقت الحالي
    fs::last_write_time("data.txt", fs::file_time_type::clock::now());
    std::cout << "تم تحديث وقت التعديل" << '\n';

    // إعادة الوقت الأصلي
    fs::last_write_time("data.txt", original_time);
    std::cout << "تم استعادة الوقت الأصلي" << '\n';
}

#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // إنشاء ملف عادي
    std::ofstream("original.txt");

    std::cout << "قبل: " << fs::hard_link_count("original.txt") << '\n'; // 1

    // إنشاء رابط صلب
    fs::create_hard_link("original.txt", "link.txt");

    std::cout << "بعد: " << fs::hard_link_count("original.txt") << '\n'; // 2
    std::cout << "الرابط: " << fs::hard_link_count("link.txt") << '\n';    // 2
    // كلاهما يشيران لنفس الملف الفعلي
}

