#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // إنشاء ملف ورابط رمزي
    std::ofstream("real.txt");
    fs::create_symlink("real.txt", "shortcut");

    // symlink_status يُرجع معلومات الرابط نفسه
    std::cout << "نوع الرابط: " << fs::is_symlink(fs::symlink_status("shortcut")) << '\n';

    // canonical يحل الرابط ويُرجع المسار الحقيقي
    std::cout << "المسار الحقيقي: " << fs::canonical("shortcut") << '\n';
}

#include <iostream>
