#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // إنشاء ملف ورابط رمزي
    std::ofstream("original.txt");
    fs::create_symlink("original.txt", "link_to_original");

    // قراءة هدف الرابط
    fs::path target = fs::read_symlink("link_to_original");
    std::cout << "الرابط يشير إلى: " << target << '\n';
    // original.txt (مسار نسبي)
}

#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    fs::path p = "some_file";

    // تحقق مما إذا كان رابطًا رمزيًا أولًا
    if (fs::is_symlink(p)) {
        fs::path target = fs::read_symlink(p);
        std::cout << p << " -> " << target << '\n';
    } else {
        std::cout << p << " ليس رابطًا رمزيًا" << '\n';
    }
}

