#include <iostream>
#include <filesystem>
namespace fs = std::filesystem;

int main() {
    // create_symlink: عام — يعمل للملفات والمجلدات
    // create_directory_symlink: خاص بالمجلدات — يُوضح القصد

    fs::create_symlink("target", "link1");           // عام
    fs::create_directory_symlink("target", "link2");  // واضح أنه مجلد

    // النسخة الخاصة لا تُنشئ رابطًا لملف عادي حتى لو كان الاسم موجودًا
    // هذا يمنع الأخطاء عند الخلط بين ملف ومجلد بنفس الاسم
}
